import { describe, it, expect } from 'vitest'
import { parseJudgeResponse } from '../judge'

describe('parseJudgeResponse', () => {
  it('parses valid JSON correctly', () => {
    const input = JSON.stringify({
      verdict: 'The council agrees.',
      divergence: [{ claim: 'Point A', agree: ['GPT-4o'], disagree: ['Claude Sonnet'], partial: [] }],
    })
    const result = parseJudgeResponse(input)
    expect(result.verdict).toBe('The council agrees.')
    expect(result.divergence).toHaveLength(1)
    expect(result.divergence[0].claim).toBe('Point A')
  })

  it('strips markdown json fences before parsing', () => {
    const inner = JSON.stringify({ verdict: 'Fenced verdict.', divergence: [] })
    const input = `\`\`\`json\n${inner}\n\`\`\``
    const result = parseJudgeResponse(input)
    expect(result.verdict).toBe('Fenced verdict.')
    expect(result.divergence).toEqual([])
  })

  it('strips plain code fences before parsing', () => {
    const inner = JSON.stringify({ verdict: 'Plain fence.', divergence: [] })
    const input = `\`\`\`\n${inner}\n\`\`\``
    const result = parseJudgeResponse(input)
    expect(result.verdict).toBe('Plain fence.')
  })

  it('falls back to raw text verdict on invalid JSON', () => {
    const input = 'This is not JSON at all.'
    const result = parseJudgeResponse(input)
    expect(result.verdict).toBe('This is not JSON at all.')
    expect(result.divergence).toEqual([])
  })

  it('falls back on empty string response', () => {
    const result = parseJudgeResponse('')
    expect(result.verdict).toBe('Synthesis unavailable')
    expect(result.divergence).toEqual([])
  })

  it('uses raw text as verdict when verdict field is missing', () => {
    const input = JSON.stringify({ divergence: [] }) // no verdict
    const result = parseJudgeResponse(input)
    // verdict field missing → falls back to raw content string
    expect(result.verdict).toBe(input)
  })

  it('sets divergence to [] when divergence field is missing', () => {
    const input = JSON.stringify({ verdict: 'Only verdict.' })
    const result = parseJudgeResponse(input)
    expect(result.verdict).toBe('Only verdict.')
    expect(result.divergence).toEqual([])
  })
})

