'use client'

import { useState } from 'react'
import type { ModelResult, DivergenceEntry } from '@/lib/types'

type Props = {
  result: ModelResult
  divergence: DivergenceEntry[]
}

const MODEL_COLORS: Record<string, string> = {
  'G':  'bg-green-500',
  'C':  'bg-orange-400',
  'Gm': 'bg-blue-500',
  'P':  'bg-purple-500',
  'D':  'bg-sky-500',
  'K':  'bg-rose-400',
}

export function ModelCard({ result, divergence }: Props) {
  const [expanded, setExpanded] = useState(false)
  const dotColor = MODEL_COLORS[result.abbreviation] ?? 'bg-gray-400'

  const divergeCount = divergence.filter(e => e.disagree.includes(result.displayName)).length

  return (
    <div className={`bg-white border rounded-lg p-4 ${!result.available ? 'opacity-50' : ''}`}>
      <div className="flex items-center gap-2 mb-3">
        <span className={`w-2 h-2 rounded-full ${dotColor}`} />
        <span className="text-xs font-bold uppercase tracking-wide text-gray-500">{result.displayName}</span>
        {divergeCount > 0 && (
          <span className="ml-auto text-xs bg-yellow-100 text-yellow-700 border border-yellow-300 rounded px-1.5 py-0.5">
            ↳ diverges on {divergeCount} {divergeCount === 1 ? 'point' : 'points'}
          </span>
        )}
      </div>

      {result.available ? (
        <>
          <p className={`text-xs leading-relaxed text-gray-600 ${expanded ? '' : 'line-clamp-4'}`}>
            {result.response}
          </p>
          {result.response.length > 200 && (
            <button
              onClick={() => setExpanded(e => !e)}
              className="mt-2 text-xs text-gray-400 hover:text-gray-600 underline"
            >
              {expanded ? 'show less' : 'read more'}
            </button>
          )}
        </>
      ) : (
        <p className="text-xs text-gray-400 italic">Unavailable — timed out or API key not set</p>
      )}
    </div>
  )
}

