'use client'

import { useState } from 'react'
import { CouncilVerdict } from '@/components/CouncilVerdict'
import { DivergenceMap } from '@/components/DivergenceMap'
import { ModelCard } from '@/components/ModelCard'
import type { CouncilResponse } from '@/lib/types'

type Phase = 'idle' | 'consulting' | 'synthesizing' | 'done' | 'error'

export default function Home() {
  const [prompt, setPrompt] = useState('')
  const [phase, setPhase] = useState<Phase>('idle')
  const [result, setResult] = useState<CouncilResponse | null>(null)
  const [errorMsg, setErrorMsg] = useState('')

  const canSubmit = prompt.trim().length > 0 && prompt.length <= 4000 && phase === 'idle'

  async function handleSubmit() {
    if (!canSubmit) return
    setPhase('consulting')
    setResult(null)
    setErrorMsg('')

    // Switch to "synthesizing" after ~20s to indicate second phase
    const synthesizingTimer = setTimeout(() => setPhase('synthesizing'), 20_000)

    try {
      const res = await fetch('/api/council', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ prompt: prompt.trim() }),
      })
      clearTimeout(synthesizingTimer)

      if (!res.ok) {
        const body = await res.json()
        throw new Error(body.error ?? 'Request failed')
      }

      const data: CouncilResponse = await res.json()
      setResult(data)
      setPhase('done')
    } catch (err) {
      clearTimeout(synthesizingTimer)
      setErrorMsg(err instanceof Error ? err.message : 'Something went wrong')
      setPhase('error')
    }
  }

  const isLoading = phase === 'consulting' || phase === 'synthesizing'
  const isSynthesisUnavailable = result?.verdict?.toLowerCase().includes('unavailable') ||
    result?.verdict?.toLowerCase().includes('no models responded') || false

  return (
    <main className="min-h-screen bg-gray-50">
