import Anthropic from '@anthropic-ai/sdk'
import { GoogleGenerativeAI } from '@google/generative-ai'
import type { ModelResult } from './types'
import { MODELS } from './models-config'

const TIMEOUT_MS = 25_000
const MAX_RESPONSE_CHARS = 6_000

function truncate(text: string): string {
  if (text.length <= MAX_RESPONSE_CHARS) return text
  return text.slice(0, MAX_RESPONSE_CHARS) + '...[truncated]'
}

function unavailable(id: string): ModelResult {
  const cfg = MODELS.find(m => m.id === id)!
  return { model: id, displayName: cfg.displayName, abbreviation: cfg.abbreviation, response: '', available: false }
}

