  const cfg = MODELS.find(m => m.envKey === 'ANTHROPIC_API_KEY')!
  const modelId = cfg.id
  if (!key) return unavailable(modelId)
  try {
    const client = new Anthropic({ apiKey: key })
    const signal = AbortSignal.timeout(TIMEOUT_MS)
    const res = await client.messages.create(
      { model: modelId, max_tokens: 1000, messages: [{ role: 'user', content: prompt }] },
      { signal },
    )
    const text = truncate(res.content[0]?.type === 'text' ? res.content[0].text : '')
    return { model: modelId, displayName: cfg.displayName, abbreviation: cfg.abbreviation, response: text, available: true }
  } catch {
    return unavailable(modelId)
  }
}

async function callGemini(prompt: string): Promise<ModelResult> {
  const key = process.env.GOOGLE_AI_API_KEY
  const cfg = MODELS.find(m => m.envKey === 'GOOGLE_AI_API_KEY')!
  const modelId = cfg.id
  if (!key) return unavailable(modelId)
  try {
    const genai = new GoogleGenerativeAI(key)
    const model = genai.getGenerativeModel({ model: modelId })
    // Gemini SDK doesn't accept AbortSignal natively; wrap in a race
    const result = await Promise.race([
      model.generateContent(prompt),
      new Promise<never>((_, reject) => setTimeout(() => reject(new Error('timeout')), TIMEOUT_MS)),
    ])
    const text = truncate((result as Awaited<ReturnType<typeof model.generateContent>>).response.text())
    return { model: modelId, displayName: cfg.displayName, abbreviation: cfg.abbreviation, response: text, available: true }
  } catch {
    return unavailable(modelId)
  }
}

async function callPerplexity(prompt: string): Promise<ModelResult> {
  const key = process.env.PERPLEXITY_API_KEY
  const modelId = 'llama-3.1-sonar-large-128k-online'
  if (!key) return unavailable(modelId)
  try {
    const text = await callOpenAICompatible(
      'https://api.perplexity.ai',
      key,
      modelId,
      prompt,
      AbortSignal.timeout(TIMEOUT_MS),
    )
    return { model: modelId, displayName: 'Perplexity', abbreviation: 'P', response: truncate(text), available: true }
  } catch {
    return unavailable(modelId)
  }
}

async function callDeepSeek(prompt: string): Promise<ModelResult> {
  const key = process.env.DEEPSEEK_API_KEY
  const modelId = 'deepseek-chat'
  if (!key) return unavailable(modelId)
  try {
    const text = await callOpenAICompatible(
      'https://api.deepseek.com',
      key,
      modelId,
      prompt,
      AbortSignal.timeout(TIMEOUT_MS),
    )
    return { model: modelId, displayName: 'DeepSeek', abbreviation: 'D', response: truncate(text), available: true }
  } catch {
    return unavailable(modelId)
  }
}

// Ollama runs locally — no API key needed, just needs `ollama serve` running
// Install: https://ollama.com — then `ollama run llama3.2` to pull the model
async function callOllama(prompt: string): Promise<ModelResult> {
  const modelId = 'llama3.2'
  const enabled = process.env.OLLAMA_ENABLED === 'true'
  if (!enabled) return unavailable(modelId)
  try {
    const text = await callOpenAICompatible(
      'http://localhost:11434',
      'ollama', // Ollama doesn't need a real key but the helper requires a string
      modelId,
      prompt,
      AbortSignal.timeout(TIMEOUT_MS),
    )
    return { model: modelId, displayName: 'Ollama (local)', abbreviation: 'O', response: truncate(text), available: true }
  } catch {
    return unavailable(modelId)
  }
}

export async function fanOut(prompt: string): Promise<ModelResult[]> {
  const results = await Promise.allSettled([
    callClaude(prompt),   // Haiku in budget config
    callGemini(prompt),   // Flash in budget config — free tier
    callDeepSeek(prompt), // Very cheap
    callOllama(prompt),   // Free if you have Ollama running
  ])
  return results.map(r => (r.status === 'fulfilled' ? r.value : unavailable((r as PromiseRejectedResult).reason)))
}

