  </div>
  <div class="stream-card">
    <div class="sc-header">
      <span class="sc-name" style="color:#e67e22">Mixtral</span>
      <div class="sc-status"><div class="status-ring ring-live"></div>Live</div>
    </div>
    <div class="sc-text">
