    </div>
  </div>
  <div class="stream-card">
    <div class="sc-header">
      <span class="sc-name" style="color:#e74c3c">Gemma 2</span>
      <div class="sc-status"><div class="status-ring ring-wait"></div>Waiting</div>
    </div>
    <div class="sc-text" style="color:#ccc; font-style:italic;">
