    </div>
  </div>
</div>

<!-- CONFIDENCE MAP -->
<div class="section-title" style="margin-top:32px;">— Confidence Map —</div>
<div class="conf-box">
  <div class="conf-card">
    <div class="conf-card-header">
      <span class="conf-card-title">Where the Council agrees vs. disagrees</span>
      <div class="conf-card-meta">
        <span class="meta-high">2 high confidence</span>
        <span>·</span>
        <span class="meta-low">1 split</span>
      </div>
    </div>

    <div class="claim-row">
      <div class="claim-content">
        <div class="claim-bar-wrap">
          <div class="claim-bar"><div class="bar-fill fill-75"></div></div>
        </div>
        <div class="claim-label">
          <span class="conf-label conf-high">High</span>
          <strong>Don't pivot cold.</strong> With 3 customers at $500/mo, you lack the enterprise proof points to justify a full motion change right now.
        </div>
      </div>
      <div class="model-dots">
        <div class="mdot mdot-agree">H</div>
        <div class="mdot mdot-agree">L</div>
        <div class="mdot mdot-agree">M</div>
        <div class="mdot mdot-pending">G</div>
      </div>
    </div>

    <div class="claim-row">
