        <div class="claim-bar-wrap">
          <div class="claim-bar"><div class="bar-fill fill-50"></div></div>
        </div>
        <div class="claim-label">
          <span class="conf-label conf-mid">Medium</span>
          <strong>Run a hybrid experiment</strong> — keep PLG while testing 5 enterprise outbound leads to measure real sales cycle cost.
        </div>
      </div>
      <div class="model-dots">
        <div class="mdot mdot-partial">H</div>
        <div class="mdot mdot-disagree">L</div>
        <div class="mdot mdot-agree">M</div>
        <div class="mdot mdot-pending">G</div>
      </div>
    </div>

    <div class="claim-row">
      <div class="claim-content">
        <div class="claim-bar-wrap">
          <div class="claim-bar"><div class="bar-fill fill-25"></div></div>
        </div>
        <div class="claim-label">
          <span class="conf-label conf-low">Split</span>
          <strong>Raise price to $1k/mo</strong> to test enterprise willingness before changing your sales motion.
        </div>
      </div>
      <div class="model-dots">
        <div class="mdot mdot-agree">H</div>
        <div class="mdot mdot-disagree">L</div>
        <div class="mdot mdot-disagree">M</div>
        <div class="mdot mdot-pending">G</div>
      </div>
    </div>
  </div>
</div>

<!-- VERDICT -->
<div class="section-title" style="margin-top:32px;">— Council Verdict —</div>
<div class="verdict-box">
  <div class="verdict-card">
    <div class="verdict-header">
      <div class="verdict-icon">⚖</div>
      <div class="verdict-title">Council Synthesis</div>
    </div>
    <div class="verdict-body">
      <div class="vpoint">
        <span class="vpoint-tag tag-high">Consensus</span>
